<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Sorting Visualizer</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    background: #0f0f13;
    color: #e0e0e0;
    font-family: system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    min-height: 100vh;
    padding: 24px;
    gap: 24px;
  }

  h1 {
    font-size: 1.4rem;
    font-weight: 600;
    color: #a78bfa;
    letter-spacing: 0.05em;
  }

  #controls {
    display: flex;
    gap: 12px;
  }

  button {
    padding: 10px 24px;
    border: none;
    border-radius: 8px;
    font-size: 0.95rem;
    font-weight: 600;
    cursor: pointer;
    transition: opacity 0.15s, transform 0.1s;
  }

  button:hover { opacity: 0.85; }
  button:active { transform: scale(0.97); }

  #sort   { background: #7c3aed; color: #fff; }
  #shuffle { background: #0ea5e9; color: #fff; }
  #reset  { background: #374151; color: #e0e0e0; }

  button:disabled { opacity: 0.4; cursor: not-allowed; }

  #bars {
    display: flex;
    align-items: flex-end;
    gap: 3px;
    width: 100%;
    max-width: 900px;
    height: 340px;
    background: #16161f;
    border-radius: 12px;
    padding: 12px 12px 0;
    border: 1px solid #2a2a3a;
  }

  .bar {
    flex: 1;
    border-radius: 3px 3px 0 0;
    background: #7c3aed;
    transition: height 0.08s ease;
    min-width: 2px;
  }

  .bar.comparing { background: #f59e0b; }
  .bar.sorted    { background: #10b981; }

  #status {
    font-size: 0.85rem;
    color: #6b7280;
    min-height: 1.2em;
  }
</style>
</head>
<body>
<h1>Sorting Algorithm Visualizer</h1>

<div id="controls">
  <button id="sort">Sort</button>
  <button id="shuffle">Shuffle</button>
  <button id="reset">Reset</button>
</div>

<div id="bars"></div>
<div id="status"></div>

<script>
(() => {
  const CONTAINER = document.getElementById('bars');
  const STATUS    = document.getElementById('status');
  const BTN_SORT  = document.getElementById('sort');
  const BTN_SHUF  = document.getElementById('shuffle');
  const BTN_RESET = document.getElementById('reset');

  const DEFAULT_SIZE = 60;

  let arr = [];
  let barEls = [];

  // --- Insertion-sort state machine ---
  let si = 1;       // outer index
  let sj = 0;       // inner index (current position of element being inserted)
  let sKey = 0;     // value being inserted
  let sDone = false;

  function resetSortState() {
    si = 1;
    sj = -1;
    sKey = arr.length > 0 ? arr[1] : 0;
    sDone = arr.length <= 1;
    clearHighlights();
  }

  function makeDefaultArray(n) {
    return Array.from({ length: n }, (_, i) => Math.round((i + 1) * (100 / n)));
  }

  function shuffle(a) {
    for (let i = a.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [a[i], a[j]] = [a[j], a[i]];
    }
    return a;
  }

  function render() {
    const max = Math.max(...arr, 1);
    CONTAINER.innerHTML = '';
    barEls = arr.map(v => {
      const el = document.createElement('div');
      el.className = 'bar';
      el.style.height = `${(v / max) * 100}%`;
      CONTAINER.appendChild(el);
      return el;
    });
  }

  function clearHighlights() {
    barEls.forEach(b => b.classList.remove('comparing', 'sorted'));
  }

  function setArray(a) {
    arr = a.slice();
    render();
    resetSortState();
    STATUS.textContent = '';
  }

  function isSorted() {
    for (let i = 1; i < arr.length; i++) {
      if (arr[i] < arr[i - 1]) return false;
    }
    return true;
  }

  // Insertion sort driven one comparison at a time.
  // State: si = outer loop index (element being placed)
  //        sj = inner loop index (scanning leftward)
  // Each call does exactly one comparison (and possibly one swap).
  function sortStep() {
    if (sDone) return true;
    if (arr.length <= 1) { sDone = true; return true; }

    clearHighlights();

    // If sj hasn't been initialised for current si, set it up.
    if (sj < 0) {
      sKey = arr[si];
      sj = si - 1;
    }

    if (sj >= 0 && arr[sj] > sKey) {
      // Shift element right
      arr[sj + 1] = arr[sj];
      updateBar(sj + 1, arr[sj + 1]);
      barEls[sj + 1].classList.add('comparing');
      barEls[sj].classList.add('comparing');
      sj--;
    } else {
      // Place key
      arr[sj + 1] = sKey;
      updateBar(sj + 1, arr[sj + 1]);
      barEls[sj + 1].classList.add('comparing');

      // Mark elements 0..si as sorted
      for (let k = 0; k <= si; k++) barEls[k].classList.add('sorted');

      si++;
      sj = -1;

      if (si >= arr.length) {
        sDone = true;
        clearHighlights();
        barEls.forEach(b => b.classList.add('sorted'));
        STATUS.textContent = 'Sorted!';
        return true;
      }
    }

    return false;
  }

  function updateBar(idx, val) {
    const max = Math.max(...arr, 1);
    barEls[idx].style.height = `${(val / max) * 100}%`;
  }

  // --- Animation loop ---
  let animId = null;
  let animating = false;

  function startAnimation() {
    if (animating) return;
    animating = true;
    BTN_SORT.disabled = true;
    BTN_SHUF.disabled = true;

    function step() {
      const done = sortStep();
      if (done) {
        animating = false;
        BTN_SORT.disabled = false;
        BTN_SHUF.disabled = false;
        return;
      }
      animId = setTimeout(step, 30);
    }
    step();
  }

  function stopAnimation() {
    if (animId !== null) { clearTimeout(animId); animId = null; }
    animating = false;
    BTN_SORT.disabled = false;
    BTN_SHUF.disabled = false;
  }

  // --- Buttons ---
  BTN_SORT.addEventListener('click', () => {
    if (sDone) return;
    startAnimation();
  });

  BTN_SHUF.addEventListener('click', () => {
    stopAnimation();
    shuffle(arr);
    render();
    resetSortState();
    STATUS.textContent = '';
  });

  BTN_RESET.addEventListener('click', () => {
    stopAnimation();
    arr = makeDefaultArray(DEFAULT_SIZE);
    render();
    resetSortState();
    STATUS.textContent = '';
  });

  // --- Public API ---
  window.viz = {
    array()      { return arr.slice(); },
    setArray(a)  { stopAnimation(); setArray(a); },
    sortStep()   { return sortStep(); },
    sorted()     { return isSorted(); },
  };

  // --- Init ---
  arr = shuffle(makeDefaultArray(DEFAULT_SIZE));
  render();
  resetSortState();
})();
</script>
</body>
</html>
